params.command:
docker exec el34-manager python3 - <<'PY'
# 조치별 위험도: 자동 vs 승인 필요
SAFE_AUTO={"enable jailbreak detector","tighten PII output filter","apply rate quota","re-validate corpus"}
RISKY={"rotate secrets","disable dangerous tools","block client","quarantine poisoned docs"}
alert_action_queue=["enable jailbreak detector","disable dangerous tools","apply rate quota","rotate secrets"]
log=[]
for a in alert_action_queue:
    if a in SAFE_AUTO:
        log.append(f"AUTO-EXEC: {a}")
    else:
        log.append(f"APPROVAL-REQUIRED: {a}")
for l in log:
    print(" "+l)
auto=sum(1 for l in log if l.startswith("AUTO"))
appr=sum(1 for l in log if l.startswith("APPROVAL"))
print(f"auto={auto} approval={appr}")
print("AUTOMATED" if auto>0 and appr>0 else "IMBALANCED")
PY
